/*
Here we will add the values to the payload which are needed for HA Gielz sensors and automation

To test this proxy, run:
% curl http://192.168.2.246:1880/properties/report
(or the applicable url)

To access original nodes:
% curl http://192.168.2.220/properties/report
% curl http://192.168.2.217/properties/report

*/

// check how many devices we have
var device_count = flow.get('device_count') || 0;

// read serial numbers from global variable
var snZendure1 = flow.get('snZendure1')||"0";
var snZendure2 = flow.get('snZendure2')||"0";
var snZendure3 = flow.get('snZendure3')||"0";

// load global variables
var latestPowerCmd = flow.get('latestPowerCmd') || 0;
var latestPowerCmd_1 = flow.get('latestPowerCmd_1') || 0;
var latestPowerCmd_2 = flow.get('latestPowerCmd_2') || 0;
var latestPowerCmd_3 = flow.get('latestPowerCmd_3') || 0;
var device_active_count = flow.get('device_active_count')||1;                              //0: no singlemode (dual mode), 1: singlemode << changed now
var singleMode_activedevice = flow.get('singleMode_activedevice')||0;    //0: device1, 1: device2
var singleMode_standby_device_A = flow.get('singleMode_standby_device_A')||0;
var singleMode_standby_device_B = flow.get('singleMode_standby_device_B')||0;
var singleMode_standby_device_C = flow.get('singleMode_standby_device_C')||0;
var dualMode_force_start_timestamp = flow.get('dualMode_force_start_timestamp') || 1;
var singleToDualModeTransition_start_timestamp = flow.get('singleToDualModeTransition_start_timestamp') || 1;
var singleModeDeviceChangeTranstion_timer = flow.get('singleModeDeviceChangeTranstion_timer') || 1;
var singleMode_upperlimit_percent = flow.get('singleMode_upperlimit_percent') || 100;
var singleMode_lowerlimit_percent = flow.get('singleMode_lowerlimit_percent') || 40;
var payloadError = flow.get('payloadError') || 0;
var equalMode = flow.get('equalMode') || 0;
var alwaysDualMode = flow.get('alwaysDualMode') || 0;
var solarPowerInfo = flow.get('solarPowerInfo') || 0;
var proxyVersion = flow.get('proxyVersion') || "0";
var dualmode_damper_enable = flow.get('dualmode_damper_enable')||0;

// Initialize local variables
let electricLevel_A = 0;
let electricLevel_B = 0;
let electricLevel_C = 0;
let electricLevel = 0;
let devices_soc = [];
let deviceTransition_active = 0;
let sn_A = "";
let sn_B = "";
let sn_C = "";
let sn = device_count + "x Zendure via PROXY";

//Create a new json object to store the original and new values
let values = {}
values.properties = {}
values.original = {}



//// add back req/res for the reply to HA

let key = "http_" + msg._msgid;
let http = flow.get(key);

if (!http) {
    //node.warn("HTTP context not found");
    return null;
}
msg.req = http.req;
msg.res = http.res;

// cleanup key
flow.set(key, null);



//// get the data from the payload objects in the right order

let dev1, dev2, dev3;

if (device_count === 1) {
    dev1 = msg.payload.zendure1;
    if (!dev1) {
        //node.warn("Zendure1 ontbreekt in de join.");
        return null;
    }
    values.original[0] = JSON.parse(JSON.stringify(dev1));

} else if (device_count === 2) {
    dev1 = msg.payload.zendure1;
    dev2 = msg.payload.zendure2;
    if (!dev1 || !dev2) {
        //node.warn("Zendure1 of Zendure2 ontbreekt in de join.");
        return null;
    }
    values.original[0] = JSON.parse(JSON.stringify(dev1));
    values.original[1] = JSON.parse(JSON.stringify(dev2));

} else if (device_count === 3) {
    dev1 = msg.payload.zendure1;
    dev2 = msg.payload.zendure2;
    dev3 = msg.payload.zendure3;
    if (!dev1 || !dev2 || !dev3) {
        //node.warn("Zendure1, 2 of 3 ontbreekt in de join.");
        return null;
    }
    values.original[0] = JSON.parse(JSON.stringify(dev1));
    values.original[1] = JSON.parse(JSON.stringify(dev2));
    values.original[2] = JSON.parse(JSON.stringify(dev3));
} else {
    node.warn("Ongeldige device_count: " + device_count);
    return null;
}
///// end logic for ordering


// move battery packdata from original data to root level, as if it is one device
// non-deep clone for speed optimization

let packData, packData1, packData2, packData3;

if (device_count === 1) {
packData1 = [...values.original[0].packData];
packData = [...packData1]

} else if (device_count === 2) {
packData1 = [...values.original[0].packData];
packData2 = [...values.original[1].packData];
packData = [...packData1, ...packData2]

} else if (device_count === 3) {
packData1 = [...values.original[0].packData];
packData2 = [...values.original[1].packData];
packData3 = [...values.original[2].packData];
packData = [...packData1, ...packData2, ...packData3]
}
values.packData = packData


// write time of this message to variable for use in "Resend POST"  
let currentTime = Math.floor(Date.now() / 1000)
flow.set('latestGETMessage_timestamp_epoch', currentTime)


//// calculate REST variables

if (device_count === 1) {

    // update current SoC levels to global variable
    electricLevel_A = (values.original[0].properties.electricLevel)
    electricLevel_B = 0
    electricLevel_C = 0
    flow.set('electricLevel_A', electricLevel_A)

} else if (device_count === 2) {

    // update current SoC levels to global variable
    electricLevel_A = (values.original[0].properties.electricLevel)
    electricLevel_B = (values.original[1].properties.electricLevel)
    electricLevel_C = 0
    flow.set('electricLevel_A', electricLevel_A)
    flow.set('electricLevel_B', electricLevel_B)

} else if (device_count === 3) {

    // update current SoC levels to global variable
    electricLevel_A = (values.original[0].properties.electricLevel)
    electricLevel_B = (values.original[1].properties.electricLevel)
    electricLevel_C = (values.original[2].properties.electricLevel)
    devices_soc = [
    { name: "device_A", soc: electricLevel_A },
    { name: "device_B", soc: electricLevel_B },
    { name: "device_C", soc: electricLevel_C }
    ];

    flow.set('electricLevel_A', electricLevel_A)
    flow.set('electricLevel_B', electricLevel_B)
    flow.set('electricLevel_C', electricLevel_C)
    flow.set('devices_soc', devices_soc)

}




// Calculate max power value used in power distribution calculation in POST messages
// maxpower can be different for in and out directions
// first get the values that are configured on the Zendures 

let chargeMaxLimit_A, chargeMaxLimit_B, chargeMaxLimit_C, inverseMaxPower_A, inverseMaxPower_B, inverseMaxPower_C, maxPower_in, maxPower_out;

if (device_count === 1) {
chargeMaxLimit_A = values.original[0].properties.chargeMaxLimit
chargeMaxLimit_B = 0
chargeMaxLimit_C = 0
inverseMaxPower_A = values.original[0].properties.inverseMaxPower
inverseMaxPower_B = 0
inverseMaxPower_C = 0
// then calculate maxpower
maxPower_in = chargeMaxLimit_A;
maxPower_out = inverseMaxPower_A;

} else if (device_count === 2) {
chargeMaxLimit_A = values.original[0].properties.chargeMaxLimit
chargeMaxLimit_B = values.original[1].properties.chargeMaxLimit
chargeMaxLimit_C = 0
inverseMaxPower_A = values.original[0].properties.inverseMaxPower
inverseMaxPower_B = values.original[1].properties.inverseMaxPower
inverseMaxPower_C = 0
// then calculate maxpower
maxPower_in = Math.min(chargeMaxLimit_A, chargeMaxLimit_B)
maxPower_out = Math.min(inverseMaxPower_A, inverseMaxPower_B)

} else if (device_count === 3) {
chargeMaxLimit_A = values.original[0].properties.chargeMaxLimit
chargeMaxLimit_B = values.original[1].properties.chargeMaxLimit
chargeMaxLimit_C = values.original[2].properties.chargeMaxLimit
inverseMaxPower_A = values.original[0].properties.inverseMaxPower
inverseMaxPower_B = values.original[1].properties.inverseMaxPower
inverseMaxPower_C = values.original[2].properties.inverseMaxPower
// then calculate maxpower
maxPower_in = Math.min(chargeMaxLimit_A, chargeMaxLimit_B, chargeMaxLimit_C)
maxPower_out = Math.min(inverseMaxPower_A, inverseMaxPower_B, inverseMaxPower_C)

}
flow.set('maxPower_in', maxPower_in)
flow.set('maxPower_out', maxPower_out)


// Version
values.proxyVersion = proxyVersion


//----- here all variables to send to HA in the response for the combined nodes



// product - we'll take the product string given by the device (Zendure 1). 
// Gielz uses this product name to determine the battery size, hence it has the be the actual product string (only in the March 2026 version).
let product = values.original[0].product;
values.product = product



let outputLimit, inputLimit, outputPackPower, outputPackPower_A, outputPackPower_B, outputPackPower_C;
let packInputPower, packInputPower_A, packInputPower_B, packInputPower_C; 
let gridInputPower, gridInputPower_A, gridInputPower_B, gridInputPower_C, outputHomePower, outputHomePower_A, outputHomePower_B, outputHomePower_C;
let minSoc_A, minSoc_B, minSoc_C, minSoc, socSet_A, socSet_B, socSet_C, socSet, socLimit_A, socLimit_B, socLimit_C, socLimit;
let electricLevel_A_calc, electricLevel_B_calc, electricLevel_C_calc;
let smartMode_A, smartMode_B, smartMode_C, smartMode, BatVolt, remainOutTime;
let hyperTmp_A, hyperTmp_B, hyperTmp_C, hyperTmp, chargeMaxLimit, inverseMaxPower, packNum, rssi, is_error;
let socStatus_A, socStatus_B, socStatus_C, socStatus, gridReverse_A, gridReverse_B, gridReverse_C, gridReverse;
let batCalTime_A, batCalTime_B, batCalTime_C, batCalTime;
let pvStatus_A, pvStatus_B, pvStatus_C, pvStatus, acStatus_A, acStatus_B, acStatus_C, acStatus, dcStatus_A, dcStatus_B, dcStatus_C, dcStatus;
let solarInputPower, solarInputPower_A, solarInputPower_B, solarInputPower_C;
let gridOffPower, gridOffPower_A, gridOffPower_B, gridOffPower_C, gridOffMode, gridOffMode_A, gridOffMode_B, gridOffMode_C;
let pass, pass_A, pass_B, pass_C;

if (device_count === 1) {

    // outputLimit (Output power limit)
    outputLimit = (values.original[0].properties.outputLimit);

    // inputLimit (AC charging power limit)
    inputLimit = (values.original[0].properties.inputLimit);

    // outputPackPower
    outputPackPower_A = values.original[0].properties.outputPackPower;
    outputPackPower = outputPackPower_A;

    // packInputPower
    packInputPower_A = values.original[0].properties.packInputPower;
    packInputPower = packInputPower_A;

    // outputPackPower (same as outputPackPower for SF2400AC, but can be different on systems with solar attached)
    gridInputPower_A = values.original[0].properties.gridInputPower;
    gridInputPower = gridInputPower_A;

    // outputHomePower (same as packInputPower for SF2400AC, but can be different on systems with solar attached)
    outputHomePower_A = values.original[0].properties.outputHomePower;
    outputHomePower = outputHomePower_A;

    // solarInputPower
    solarInputPower_A = values.original[0].properties.solarInputPower;
    solarInputPower = solarInputPower_A;

    // gridOffPower
    gridOffPower_A = values.original[0].properties.gridOffPower;
    gridOffPower = gridOffPower_A;

    // gridOffMode (not always present)
    // "Zendure 2400 AC Offgrid Modus"
    // states = { 0: "Normaal", 1: "Eco", 2: "Uitgeschakeld" }
    if ("gridOffMode" in values.original[0].properties) {
        gridOffMode = values.original[0].properties.gridOffMode;
        values.properties.gridOffMode = gridOffMode;
        values.properties.gridOffMode_1 = gridOffMode;
        values.properties.gridOffMode_2 = 2;
        values.properties.gridOffMode_3 = 2;
    } else {
        values.properties.gridOffMode = 2;
        values.properties.gridOffMode_1 = 2;
        values.properties.gridOffMode_2 = 2;
        values.properties.gridOffMode_3 = 2;
    }


    // minSoc - select largest one
    minSoc_A = values.original[0].properties.minSoc;
    minSoc = minSoc_A;

    // socSet - select lowest one
    socSet_A = values.original[0].properties.socSet;
    socSet = socSet_A;

    // socLimit 	int 	0: Normal state, 1: Charge limit reached, 2: Discharge limit reached
    socLimit_A = values.original[0].properties.socLimit
    socLimit = socLimit_A;

    //// total battery percentage to send to HA
    electricLevel = electricLevel_A;

    // smartMode
    smartMode_A = values.original[0].properties.smartMode;
    smartMode = smartMode_A;

    // BatVolt
    BatVolt = values.original[0].properties.BatVolt;

    // remainOutTime
    remainOutTime = values.original[0].properties.remainOutTime;

    // hyperTmp
    hyperTmp_A = values.original[0].properties.hyperTmp;
    hyperTmp = hyperTmp_A;

    // chargeMaxLimit
    chargeMaxLimit = chargeMaxLimit_A;

    // inverseMaxPower (Maximum output power limit)
    inverseMaxPower = inverseMaxPower_A;

    // packNum
    packNum = values.original[0].properties.packNum;

    // rssi, use the lowest of both rssi's
    rssi = values.original[0].properties.rssi;

    // is_error (normaal 0; als er een >0 is, dan is het dat)
    is_error = values.original[0].properties.is_error;

    // save socStatus for both devices to a global variable (socStatus 	int 	0: No, 1: Calibrating)
    socStatus_A = values.original[0].properties.socStatus;
    // socStatus (0: No, 1: Calibrating)
    socStatus = socStatus_A;

    // Pass the pvStatus value if present
    if ("pvStatus" in values.original[0].properties) {
        pvStatus_A = values.original[0].properties.pvStatus;
        pvStatus = pvStatus_A;
        values.properties.pvStatus = pvStatus
    }

    // Pass the acStatus value if present
    if ("acStatus" in values.original[0].properties) {
        acStatus_A = values.original[0].properties.acStatus;
        acStatus = acStatus_A;
        values.properties.acStatus = acStatus
    }

    // Pass the dcStatus value if present
    if ("dcStatus" in values.original[0].properties) {
        dcStatus_A = values.original[0].properties.dcStatus;
        dcStatus = dcStatus_A;
        values.properties.dcStatus = dcStatus
    }

    //// Solar specific information
    if (solarPowerInfo === 1) {

        // Solar Power
        values.properties.solarPower1 = values.original[0].properties.solarPower1;
        values.properties.solarPower2 = values.original[0].properties.solarPower2;
        values.properties.solarPower3 = values.original[0].properties.solarPower3;
        values.properties.solarPower4 = values.original[0].properties.solarPower4;
        // skip 5 and 6 because those are not present on current device models
        values.properties.solarPower7 = 0;
        values.properties.solarPower8 = 0;
        values.properties.solarPower9 = 0;
        values.properties.solarPower10 = 0;

        values.properties.solarPower13 = 0;
        values.properties.solarPower14 = 0;
        values.properties.solarPower15 = 0;
        values.properties.solarPower16 = 0;
    }

    // gridReverse; Reverse flow control (0-2) (RW); (Probable meaning: controls if you deliver power back to the grid from solar when battery is at 100%)
    // "PV gaat enkel direct naar het net als batterij 100% is en gridReverse 1"
    gridReverse_A = values.original[0].properties.gridReverse;
    gridReverse = gridReverse_A;

    // pass
    // has to be equal to send the value, otherwise send -1 (unknown)
    if ("pass" in values.original[0].properties) {
        pass_A = values.original[0].properties.pass;
        pass = pass_A
        values.properties.pass = pass;
    }

    // batCalTime (op SF2400AC beschikbaar vanaf firmware V1.0.19)
    // Kalibratie tijd in minuten vanaf 00:00 uur
    if ("batCalTime" in values.original[0].properties) {
        batCalTime_A = values.original[0].properties.batCalTime;
        batCalTime = batCalTime_A;

        values.properties.batCalTime = batCalTime;
        values.properties.batCalTime_1 = batCalTime_A;
        values.properties.batCalTime_2 = 0;
        values.properties.batCalTime_3 = 0;
    } else {
        values.properties.batCalTime = 0;
        values.properties.batCalTime_1 = 0;
        values.properties.batCalTime_2 = 0;
        values.properties.batCalTime_3 = 0;
    }

} else if (device_count === 2) {

    // outputLimit (Output power limit)
    outputLimit = (values.original[0].properties.outputLimit + values.original[1].properties.outputLimit);

    // inputLimit (AC charging power limit)
    inputLimit = (values.original[0].properties.inputLimit + values.original[1].properties.inputLimit);

    // outputPackPower
    outputPackPower_A = values.original[0].properties.outputPackPower;
    outputPackPower_B = values.original[1].properties.outputPackPower;
    outputPackPower = (outputPackPower_A + outputPackPower_B);

    // packInputPower
    packInputPower_A = values.original[0].properties.packInputPower;
    packInputPower_B = values.original[1].properties.packInputPower;
    packInputPower = (packInputPower_A + packInputPower_B);

    // outputPackPower (same as outputPackPower for SF2400AC, but can be different on systems with solar attached)
    gridInputPower_A = values.original[0].properties.gridInputPower;
    gridInputPower_B = values.original[1].properties.gridInputPower;
    gridInputPower = (gridInputPower_A + gridInputPower_B);

    // outputHomePower (same as packInputPower for SF2400AC, but can be different on systems with solar attached)
    outputHomePower_A = values.original[0].properties.outputHomePower;
    outputHomePower_B = values.original[1].properties.outputHomePower;
    outputHomePower = (outputHomePower_A + outputHomePower_B);

    // solarInputPower
    solarInputPower_A = values.original[0].properties.solarInputPower;
    solarInputPower_B = values.original[1].properties.solarInputPower;
    solarInputPower = (solarInputPower_A + solarInputPower_B);

    // gridOffPower
    gridOffPower_A = values.original[0].properties.gridOffPower;
    gridOffPower_B = values.original[1].properties.gridOffPower;
    gridOffPower = (gridOffPower_A + gridOffPower_B);

    // gridOffMode (not always present)
    // "Zendure 2400 AC Offgrid Modus"
    // states = { 0: "Normaal", 1: "Eco", 2: "Uitgeschakeld" }
    if ("gridOffMode" in values.original[0].properties && "gridOffMode" in values.original[1].properties) {

        gridOffMode_A = values.original[0].properties.gridOffMode;
        gridOffMode_B = values.original[1].properties.gridOffMode;

        let gridOffMode_array = [gridOffMode_A, gridOffMode_B];

        // Count the amount of each value
        let count0 = gridOffMode_array.filter(v => v === 0).length;
        let count1 = gridOffMode_array.filter(v => v === 1).length;
        let count2 = gridOffMode_array.filter(v => v === 2).length;

        // Rule 1: if one or more is 0, result is 0
        if (count0 > 0) {
            gridOffMode = 0;
        }

        // Rule 2: 1 times "1" and the rest "2"
        else if ((count1 === 1) && (count1 + count2 === 2)) {
            gridOffMode = 1;
        }

        // Rule 3: all two the same
        else if (count0 === 2 || count1 === 2 || count2 === 2) {
            gridOffMode = gridOffMode_array[0];
        }

        // assign the values
        values.properties.gridOffMode = gridOffMode;
        values.properties.gridOffMode_1 = gridOffMode_A;
        values.properties.gridOffMode_2 = gridOffMode_B;
        values.properties.gridOffMode_3 = 2;
    } else {
        values.properties.gridOffMode = 2;
        values.properties.gridOffMode_1 = 2;
        values.properties.gridOffMode_2 = 2;
        values.properties.gridOffMode_3 = 2;
    }

    // minSoc - select largest one
    minSoc_A = values.original[0].properties.minSoc;
    minSoc_B = values.original[1].properties.minSoc;
    minSoc = Math.max(minSoc_A, minSoc_B);

    // socSet - select lowest one
    socSet_A = values.original[0].properties.socSet;
    socSet_B = values.original[1].properties.socSet;
    socSet = Math.min(socSet_A, socSet_B);

    // socLimit 	int 	0: Normal state, 1: Charge limit reached, 2: Discharge limit reached
    socLimit_A = values.original[0].properties.socLimit
    socLimit_B = values.original[1].properties.socLimit

    if (socLimit_A === 0 && socLimit_B === 0) {
        socLimit = 0
    } else if (socLimit_A === 1 && socLimit_B === 1) {
        socLimit = 1
    } else if (socLimit_A === 2 && socLimit_B === 2) {
        socLimit = 2
    } else if (socLimit_A === 1 || socLimit_B === 1) {
        socLimit = 0
    } else if (socLimit_A === 2 || socLimit_B === 2) {
        socLimit = 0
    } else {
        socLimit = -1 // unknown
    }


    //// total battery percentage to send to HA

    electricLevel_A_calc = electricLevel_A
    electricLevel_B_calc = electricLevel_B

    // to solve specific situation when one node drops % suddenly far below minSoc while the other one did not reach minSoc yet, or one is already below minSoc.
    // this should make the higher battery still discharge towards minSoc. After that, SoC protection can come into action to charge the lowest one up towards minSoc.
    if ((socLimit_A == 2) !== (socLimit_B == 2)) {
        if (socLimit_A == 2) {
            electricLevel_A_calc = minSoc / 10;
        } else {
            electricLevel_B_calc = minSoc / 10;
        }
    }

    if (((socLimit_A == 2) !== (socLimit_B == 2)) && (electricLevel_A_calc <= minSoc / 10 + 1 && electricLevel_B_calc <= minSoc / 10 + 1)) {   //XOR, when only one of both devices reached battery Empty state AND % not > minsoc+1
        // round up in a special case, so that minSoc will be reached when dischaging
        electricLevel = Math.ceil((electricLevel_A_calc + electricLevel_B_calc) / 2); // then we round up, so that discharging will continue till both are empty
    } else {  
        // round down in the normal case
        electricLevel = Math.floor((electricLevel_A_calc + electricLevel_B_calc) / 2);
    }


    // smartMode
    // We will send 0 if one of the nodes is at 0 (then it needs to be corrected to 1 by an HA POST command)
    // But in singleMode, if one is in smartmode=0 and the other 1, we say it is 1 (so that one device can go in Standby mode and HA does not correct it)
    // Doc: https://github.com/Zendure/zenSDK/blob/main/docs/en_properties.md
    //1: The setting parameter is not written to flash. After an unexpected power loss and restart, the device will use the value stored in flash. 
    //0: The setting parameter is written to flash.

    // also durin transition period send smartMode=1 to HA if at least one of devices has smartMode=1.
    if ((currentTime - singleToDualModeTransition_start_timestamp < singleModeDeviceChangeTranstion_timer + 10) || (currentTime - dualMode_force_start_timestamp < singleModeDeviceChangeTranstion_timer + 10)) {  //check for transition being active
        deviceTransition_active = 1;
    }

    smartMode_A = values.original[0].properties.smartMode;
    smartMode_B = values.original[1].properties.smartMode;
    if (singleMode_standby_device_A == 1 || singleMode_standby_device_B == 1 || deviceTransition_active == 1) {
        smartMode = Math.max(smartMode_A,smartMode_B);  // if at least one is in smartmode=1, send smartmode=1
    } else {
        smartMode = smartMode_A * smartMode_B; // if at least one is in smartmode=0, send smartmode=0
    }


    // BatVolt
    BatVolt = Math.floor((values.original[0].properties.BatVolt + values.original[1].properties.BatVolt) / 2);

    // remainOutTime
    remainOutTime = Math.floor((values.original[0].properties.remainOutTime + values.original[1].properties.remainOutTime) / 2);

    // hyperTmp (take the highest value)
    hyperTmp_A = values.original[0].properties.hyperTmp;
    hyperTmp_B = values.original[1].properties.hyperTmp;
    hyperTmp = Math.max(hyperTmp_A, hyperTmp_B);

    // chargeMaxLimit
    chargeMaxLimit = (chargeMaxLimit_A + chargeMaxLimit_B);

    // inverseMaxPower (Maximum output power limit)
    inverseMaxPower = (inverseMaxPower_A + inverseMaxPower_B);

    // packNum
    packNum = (values.original[0].properties.packNum + values.original[1].properties.packNum);

    // rssi, use the lowest of both rssi's
    rssi = Math.min(values.original[0].properties.rssi, values.original[1].properties.rssi);

    // is_error (normaal 0; als er een >0 is, dan is het dat)
    is_error = Math.max(values.original[0].properties.is_error, values.original[1].properties.is_error);

    // save socStatus for both devices to a global variable (socStatus 	int 	0: No, 1: Calibrating)
    socStatus_A = values.original[0].properties.socStatus;
    socStatus_B = values.original[1].properties.socStatus;
    // socStatus (0: No, 1: Calibrating)
    socStatus = Math.min(socStatus_A, socStatus_B);

    // Pass the pvStatus value if present
    if ("pvStatus" in values.original[0].properties && "pvStatus" in values.original[1].properties) {
        pvStatus_A = values.original[0].properties.pvStatus;
        pvStatus_B = values.original[1].properties.pvStatus;
        pvStatus = Math.max(pvStatus_A, pvStatus_B);
        values.properties.pvStatus = pvStatus
    }

    // Pass the acStatus value if present
