            if ((forcedDualModeActive != 1 && (singleMode_activedevice != singleMode_activedevice_previous) && device_active_count_previous == 1 && (socLimit_A != 1 && socLimit_B != 1) && (!(smartMode_A == 0 && smartMode_B == 0)))) { 
