            }

            // if only one device is Empty (may still be minSoc+1 % in some cases), make sure that the other device becomes marked as the singleMode_highestdevice to be discharged
            if ((socLimit_A == 2) !== (socLimit_B == 2)) {   //XOR, when only one of both devices reached battery Empty state
                if (socLimit_A == 2) {
                    singleMode_activedevice = 1 //device B
                } else {
                    singleMode_activedevice = 0 //device A
                }
            } else if (electricLevel_A > electricLevel_B) {
                if (electricLevel_A - electricLevel_B >= singleMode_change_device_diff_used || device_active_count_previous == 2 || (smartMode_A == 0 && smartMode_B == 0)) {  // to change device less often, we will require % diff to be higher to change
                    singleMode_activedevice = 0 //device A
                } else {
                    singleMode_activedevice = singleMode_activedevice_previous;
                }
            } else if (electricLevel_A < electricLevel_B) {
                if (electricLevel_B - electricLevel_A >= singleMode_change_device_diff_used || device_active_count_previous == 2 || (smartMode_A == 0 && smartMode_B == 0)) {  // to change device less often, we will require % diff to be higher to change
                    singleMode_activedevice = 1 //device B
                } else {
                    singleMode_activedevice = singleMode_activedevice_previous;
                }
            } else {
                singleMode_activedevice = singleMode_activedevice_previous;
            }
            flow.set('singleMode_activedevice', singleMode_activedevice)

            // save active_device in array, same as with 3 devices. This is used later for the timestamp zero power setting only for the non-active devices.
            if (singleMode_activedevice === 0) {  //device A
                devices_active = [
                    { name: "device_A", soc: electricLevel_A }
                ];
            } else if (singleMode_activedevice === 1) {  //device B
                devices_active = [
                    { name: "device_B", soc: electricLevel_B }
                ];
            }
            flow.set('devices_active', devices_active);


            // at change of active device in single mode, trigger dual mode for x seconds for a smoother transition
            if ((forcedDualModeActive != 1 && (singleMode_activedevice != singleMode_activedevice_previous) && device_active_count_previous == 1 && (socLimit_A != 2 && socLimit_B != 2) && (!(smartMode_A == 0 && smartMode_B == 0)))) {
                device_active_count = 2;
                dualMode_force_start_timestamp = currentTime;  // set timestamp as start of forced dual mode at single mode device change
                dualMode_force_original_device = singleMode_activedevice_previous
                forcedDualModeActive = 1
                flow.set('dualMode_force_start_timestamp', dualMode_force_start_timestamp)
                flow.set('dualMode_force_original_device', dualMode_force_original_device)
            }

        } else {  // device_active_count == 2 here (Dual Mode)  // Trigger single to dual mode transition
            if (device_active_count_previous == 1 && singleToDualModeTransition_active != 1 && forcedDualModeActive != 1 && !(smartMode_A == 0 && smartMode_B == 0) && !(latestPowerCmd_1_previous == 0 && latestPowerCmd_2_previous == 0) ) {   //transition from single to dual mode and not already in transition or sleep mode or previous in zero power
                singleToDualModeTransition_start_timestamp = currentTime;
                singleToDualModeTransition_original_device = singleMode_activedevice_previous
                singleToDualModeTransition_active = 1
                flow.set('singleToDualModeTransition_start_timestamp', singleToDualModeTransition_start_timestamp)
                flow.set('singleToDualModeTransition_original_device', singleToDualModeTransition_original_device)

            }

            // save active_devices in array, same as with 3 devices. This is used later for the timestamp zero power setting only for the non-active devices.
            devices_active = [
                { name: "device_A", soc: electricLevel_A },
                { name: "device_B", soc: electricLevel_B }
            ];
            flow.set('devices_active', devices_active);

        }


        if (outputLimit === 0) {
            Power_A = 0;
            Power_B = 0;
        } else {

            //// TRANSITION TO ADD NEW DEVICE (single device to dual device)
            if (singleToDualModeTransition_active == 1) {  //during transition from single to dual mode, let the original device have most of the power

                if (currentTime - singleToDualModeTransition_start_timestamp < singleModeDeviceChangeTranstion_timer * 0.75) {  // first start with most power on original device

                    if (singleToDualModeTransition_original_device == 0) {
                        Avail_A = 95;
                        Avail_B = 5;
                    } else {
                        Avail_A = 5;
                        Avail_B = 95;
                    }
                } else {  //end the singleToDualModeTransition_active period with more power to the new device, before the old device goes to equal power
                    if (singleToDualModeTransition_original_device == 0) {
                        Avail_A = 75;
                        Avail_B = 25;
                    } else {
                        Avail_A = 25;
                        Avail_B = 75;
                    }
                }
                balancingFactor = 1 // just give proportional power, no extra balancingFactor


                //// TRANSITION TO ADD NEW DEVICE (single device to new single device)
            } else if (forcedDualModeActive == 1) {    // during forced dual mode due to switch of singlemode device, we want to give the original device most of the power
                // while the new device is waking up
                if (currentTime - dualMode_force_start_timestamp < singleModeDeviceChangeTranstion_timer * 0.57) {  // first start with most power on original device

                    if (dualMode_force_original_device == 0) {
                        Avail_A = 95;
                        Avail_B = 5;
                    } else {
                        Avail_A = 5;
                        Avail_B = 95;
                    }

                } else if (currentTime - dualMode_force_start_timestamp < singleModeDeviceChangeTranstion_timer * 0.71) { // transition slowly to new device

                    if (dualMode_force_original_device == 0) {
                        Avail_A = 75;
                        Avail_B = 25;
                    } else {
                        Avail_A = 25;
                        Avail_B = 75;
                    }

                } else if (currentTime - dualMode_force_start_timestamp < singleModeDeviceChangeTranstion_timer * 0.85) { // transition slowly to new device 
                    Avail_A = 50;
                    Avail_B = 50;

                } else {  //end the forcedDualModeActive period with more power to the new device, before the old device goes to zero

                    if (dualMode_force_original_device == 0) {
                        Avail_A = 25;
                        Avail_B = 75;
                    } else {
                        Avail_A = 75;
                        Avail_B = 25;
                    }
                }
                balancingFactor = 1 // just give proportional power, no extra balancingFactor
            //// END OF TRANSITION TO ADD NEW DEVICE


            } else {   // normal case
                Avail_A = electricLevel_A - minSoc/10  // available charge stored
                if (Avail_A < 0 || socStatus_A == 1) { // also make zero when device is Calibrating
                    Avail_A = 0
                }
                Avail_B = electricLevel_B - minSoc/10  // available charge stored
                if (Avail_B < 0 || socStatus_B == 1) { // also make zero when device is Calibrating
                    Avail_B = 0
                }

                //in singleMode, let the non-active device be zero, so that the active takes all
                if (device_active_count == 1) {
                    if (singleMode_activedevice === 0) { //device A is active
                    Avail_A = 1
                    Avail_B = 0
                    } else { //device B is active
                    Avail_B = 1
                    Avail_A = 0
                    }
                }
            }

            //calculation for power A and B
            if ((Avail_A == Avail_B) || (dualmode_equal_power_discharging === 1 && (device_active_count === 2))) {
                Power_A = outputLimit / 2;
                if (Power_A > maxPower_out) {
                    Power_A = maxPower_out;
                }
                Power_B = Power_A
            } else {   // unequal charge available to discharge

                // Step 0: apply nonlinear weighting
                let weight_A = Math.pow(Avail_A, balancingFactor);
                let weight_B = Math.pow(Avail_B, balancingFactor);

                // Prevent division by zero
                let sumWeight = weight_A + weight_B;

                // Step 1: proportional distribution
                if (sumWeight > 0) {
                    Power_A = outputLimit * (weight_A / sumWeight);
                    Power_B = outputLimit * (weight_B / sumWeight);
                }

                // Step 2: apply max limit
                Power_A = Math.min(Power_A, maxPower_out);
                Power_B = Math.min(Power_B, maxPower_out);

                // Step 3: redistribute leftover power
                let used = Power_A + Power_B;
                let remaining = outputLimit - used;

                if (remaining > 0) {
                    if (Power_A < maxPower_out) {
                        let extraA = Math.min(maxPower_out - Power_A, remaining);
                        Power_A += extraA;
                        remaining -= extraA;
                    }

                    if (remaining > 0 && Power_B < maxPower_out) {
                        let extraB = Math.min(maxPower_out - Power_B, remaining);
                        Power_B += extraB;
                        remaining -= extraB;
                    }
                }

            }

            // Output
            Power_A = Math.floor(Power_A);
            Power_B = Math.floor(Power_B);


            //in singleMode, let the non-active device be zero Power
            if (device_active_count == 1) {
                if (singleMode_activedevice === 0) { //device A is active
                Power_B = 0
                } else { //device B is active
                Power_A = 0
                }

            }

            // if Avail_A and Avail_B are both zero, let the Power be also zero on both (avoids standby device to be taken out of Standby when minsoc reached)
            if ((Avail_A === 0 && Avail_B === 0) || (socLimit_A == 2 && socLimit_B == 2)) {
                Power_A = 0
                Power_B = 0
            }

        }
    /////////////////////////////////////////////////////////////////////////////////////////////////////
    } else if (device_count === 3) {
        // code for 3 devices




        // manage device_active_count status

        if (dualmode_force_discharging === 1 || device_active_count > device_count) {
            device_active_count = device_count;

        } else if (outputLimit < singleMode_lowerlimit_in) {
            device_active_count = 1;
        } else if (outputLimit > dualMode_upperlimit_in) {
            device_active_count = 3;
        } else if (device_active_count === 1) {
            if (outputLimit > singleMode_upperlimit_in ) {
                device_active_count = 2;
            }
        } else if (device_active_count === 3) {
            if (outputLimit < dualMode_lowerlimit_in ) {
                device_active_count = 2;
            }
        }
        flow.set('device_active_count', device_active_count)


        // When discharging with one device at minSoc, set the singleMode_change_device_diff_used to 1
        if (socLimit_A == 2 || socLimit_B == 2 || socLimit_C == 2) {
            singleMode_change_device_diff_used = 1;
        } else {
            singleMode_change_device_diff_used = singleMode_change_device_diff;
        }


        // calculation for power A, B and C


        // devices_soc looks like this:
        //devices_soc = [
        //    { name: "device_A", soc: electricLevel_A },
        //    { name: "device_B", soc: electricLevel_B },
        //    { name: "device_C", soc: electricLevel_C }
        //];

        /// check if soc diff between highest and lowest is >= 5%
        let socValues = devices_soc.map(d => d.soc);
        let socDiff = Math.max(...socValues) - Math.min(...socValues);

        // re-check which devices should be active when soc diff is too large or when number of (active) devices changed
        // or when active_device_count is not the same as the number of elements in devices_active
        if (socDiff >= singleMode_change_device_diff_used || device_active_count != device_active_count_previous
            || device_count != device_count_previous || device_active_count != devices_active.length) {   

            // sort devices by soc ascending for charging (low to high)
            //let sorted = [...devices_soc].sort((a, b) => a.soc - b.soc);

            // sort devices by soc descending for discharging (high to low)
            let sorted = [...devices_soc].sort((a, b) => b.soc - a.soc);

            // select active devices
            let devices_active = sorted.slice(0, device_active_count);
            flow.set('devices_active', devices_active);

            // active device is coded as binary mask (3 bits) to indicate which is active: 
            // Zendure3 Zendure2 Zendure1
            // 0 - 000 - none
            // 1 - 001 - Zendure 1
            // 2 - 010 - Zendure 2
            // 3 - 011 - Zendure 2 and Zendure 1 / Both
            // 4 - 100 - Zendure 3
            // 5 - 101 - Zendure 3 and Zendure 1
            // 6 - 110 - Zendure 3 and Zendure 2
            // 7 - 111 - All 3 Zendures

            // bitmask mapping for calculating singleMode_activedevice value
            const deviceMap = {
                device_A: 1,
                device_B: 2,
                device_C: 4
            };

            // compute bitmask for singleMode_activedevice value
            let singleMode_activedevice = devices_active.reduce((mask, d) => {
                return mask | (deviceMap[d.name] || 0);
            }, 0);

            flow.set('singleMode_activedevice', singleMode_activedevice);

        }


        // Determine available room for discharging
        Avail_A = electricLevel_A - minSoc / 10  // available charge stored
        if (Avail_A < 0 || socStatus_A == 1) { // also make zero when device is Calibrating
            Avail_A = 0
        }
        Avail_B = electricLevel_B - minSoc / 10  // available charge stored
        if (Avail_B < 0 || socStatus_B == 1) { // also make zero when device is Calibrating
            Avail_B = 0
        }
        Avail_C = electricLevel_C - minSoc / 10  // available charge stored
        if (Avail_C < 0 || socStatus_C == 1) { // also make zero when device is Calibrating
            Avail_C = 0
        }

        // set the non-active devices to zero available, so they get none of the power share
        if (!(devices_active.some(d => d.name === "device_A"))) {
            Avail_A = 0;
        }
        if (!(devices_active.some(d => d.name === "device_B"))) {
            Avail_B = 0;
        }
        if (!(devices_active.some(d => d.name === "device_C"))) {
            Avail_C = 0;
        }




        // Calculate Power based on available space
        if (Avail_A === 0 && Avail_B === 0 && Avail_C === 0) {
            Power_A = 0;
            Power_B = 0;
            Power_C = 0;
        } else if ((Avail_A == Avail_B && Avail_B == Avail_C) || (dualmode_equal_power_discharging === 1)) {
            Power_A = Math.floor(outputLimit / device_count);
            if (Power_A > maxPower_out) {
                Power_A = maxPower_out;
            }
            Power_B = Power_A;
            Power_C = Power_A;

        } else {

            // Step 0: apply nonlinear weighting
            let weight_A = Math.pow(Avail_A, balancingFactor);
            let weight_B = Math.pow(Avail_B, balancingFactor);
            let weight_C = Math.pow(Avail_C, balancingFactor);

            let sumWeight = weight_A + weight_B + weight_C;

            // Step 1: proportional distribution (Prevent division by zero)
            if (sumWeight > 0) {
                Power_A = outputLimit * (weight_A / sumWeight);
                Power_B = outputLimit * (weight_B / sumWeight);
                Power_C = outputLimit * (weight_C / sumWeight);
            } else {
                Power_A = 0;
                Power_B = 0;
                Power_C = 0;
            }

            // Step 2: apply max limit
            Power_A = Math.min(Power_A, maxPower_out);
            Power_B = Math.min(Power_B, maxPower_out);
            Power_C = Math.min(Power_C, maxPower_out);

            // Step 3: redistribute leftover power
            let used = Power_A + Power_B + Power_C;
            let remaining = outputLimit - used;

            while (remaining > 0.5) {

                let headroom_A = maxPower_out - Power_A;
                let headroom_B = maxPower_out - Power_B;
                let headroom_C = maxPower_out - Power_C;

                let totalHeadroom = 0;
                if (headroom_A > 0) totalHeadroom += weight_A;
                if (headroom_B > 0) totalHeadroom += weight_B;
                if (headroom_C > 0) totalHeadroom += weight_C;

                if (totalHeadroom === 0) break;

                let addA = headroom_A > 0 ? remaining * (weight_A / totalHeadroom) : 0;
                let addB = headroom_B > 0 ? remaining * (weight_B / totalHeadroom) : 0;
                let addC = headroom_C > 0 ? remaining * (weight_C / totalHeadroom) : 0;

                addA = Math.min(addA, headroom_A);
                addB = Math.min(addB, headroom_B);
                addC = Math.min(addC, headroom_C);

                Power_A += addA;
                Power_B += addB;
                Power_C += addC;

                remaining -= (addA + addB + addC);
            }
        }

        // Output
        Power_A = Math.floor(Power_A);
        Power_B = Math.floor(Power_B);
        Power_C = Math.floor(Power_C);


    }    
    data1.properties.outputLimit = Power_A
    data2.properties.outputLimit = Power_B
    data3.properties.outputLimit = Power_C


    //saving power posted and posted to both devices, for including in REST API status message
    latestPowerCmd = outputLimit * -1
    latestPowerCmd_1 = Power_A * -1
    latestPowerCmd_2 = Power_B * -1
    latestPowerCmd_3 = Power_C * -1
    flow.set('latestPowerCmd', latestPowerCmd)
    flow.set('latestPowerCmd_1', latestPowerCmd_1)
    flow.set('latestPowerCmd_2', latestPowerCmd_2)
    flow.set('latestPowerCmd_3', latestPowerCmd_3)

}



